func UnaryAuthInterceptor(validator *TokenValidator) grpc.UnaryServerInterceptor {
	return func(
		ctx context.Context,
		req interface{},
		info *grpc.UnaryServerInfo,
		handler grpc.UnaryHandler,
	) (interface{}, error) {
		// Skip auth for health check
		if info.FullMethod == "/mesh.MeshService/HealthCheck" {
			return handler(ctx, req)
		}

		identity, err := authenticate(ctx, validator)
		if err != nil {
			log.Printf("Authentication failed for %s: %v", info.FullMethod, err)
			return nil, err
		}

		log.Printf("Authenticated request from service=%s namespace=%s method=%s",
			identity.ServiceName, identity.Namespace, info.FullMethod)

		// Check permission for the method
		if err := authorizeMethod(identity, info.FullMethod); err != nil {
			return nil, err
		}

		newCtx := ContextWithIdentity(ctx, identity)
		return handler(newCtx, req)
	}
}

func StreamAuthInterceptor(validator *TokenValidator) grpc.StreamServerInterceptor {
	return func(
		srv interface{},
		ss grpc.ServerStream,
		info *grpc.StreamServerInfo,
		handler grpc.StreamHandler,
	) error {
		identity, err := authenticate(ss.Context(), validator)
		if err != nil {
			log.Printf("Stream authentication failed for %s: %v", info.FullMethod, err)
			return err
		}

		log.Printf("Authenticated stream from service=%s namespace=%s method=%s",
			identity.ServiceName, identity.Namespace, info.FullMethod)

		if err := authorizeMethod(identity, info.FullMethod); err != nil {
			return err
		}

		wrapped := &authenticatedServerStream{
			ServerStream: ss,
			ctx:          ContextWithIdentity(ss.Context(), identity),
		}
		return handler(srv, wrapped)
	}
}

type authenticatedServerStream struct {
	grpc.ServerStream
	ctx context.Context
}

func (s *authenticatedServerStream) Context() context.Context {
	return s.ctx
}

func authenticate(ctx context.Context, validator *TokenValidator) (*ServiceIdentity, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	// Extract authorization token
	authValues := md.Get(authHeader)
	if len(authValues) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authorization header")
	}

	authValue := authValues[0]
	if !strings.HasPrefix(authValue, tokenPrefix) {
		return nil, status.Error(codes.Unauthenticated, "invalid authorization scheme, expected MeshToken")
	}

	token := strings.TrimPrefix(authValue, tokenPrefix)

	// Validate the token
	identity, err := validator.ValidateToken(token)
	if err != nil {
		return nil, status.Errorf(codes.Unauthenticated, "token validation failed: %v", err)
	}

	// Optionally verify x-service-name matches token identity
	serviceNames := md.Get(serviceHeader)
	if len(serviceNames) > 0 && serviceNames[0] != identity.ServiceName {
		return nil, status.Error(codes.Unauthenticated, "service name mismatch between header and token")
	}

	// Log request ID if present
	requestIDs := md.Get(requestIDHeader)
	if len(requestIDs) > 0 {
		log.Printf("Request ID: %s from service: %s", requestIDs[0], identity.ServiceName)
	}

	return identity, nil
}

func authorizeMethod(identity *ServiceIdentity, method string) error {
	// Define method-to-permission mapping
	methodPermissions := map[string]string{
		"/mesh.MeshService/GetData":       "read",
		"/mesh.MeshService/SendData":      "write",
		"/mesh.MeshService/StreamData":    "read",
		"/mesh.MeshService/AdminAction":   "admin",
		"/mesh.MeshService/GenerateToken": "admin",
	}

	requiredPerm, exists := methodPermissions[method]
	if !exists {
		// Default: require read permission for unknown methods
		requiredPerm = "read"
	}

	for _, perm := range identity.Permissions {
		if perm == requiredPerm || perm == "admin" {
			return nil
		}
	}

	return status.Errorf(codes.PermissionDenied,
		"service %s lacks required permission '%s' for method %s",
		identity.ServiceName, requiredPerm, method)
}

